const leadsRaw = $('Get Accepted Leads').first().json;
const snapRaw = $('Get Snapshot').first().json;
const leads = leadsRaw.data || leadsRaw.leads || leadsRaw || [];
const arr = Array.isArray(leads) ? leads : [];
const snap = snapRaw.data || snapRaw;
const risk = snap.risk || {};
const riskAction = risk.action || 'NORMAL';
const riskScore = risk.score || 0;
if (arr.length === 0) {
  return [{ json: { claudeBody: null, leadsCount: 0 } }];
}
const leadsJson = JSON.stringify(arr.map(l => ({
  name: (l.firstName || '') + ' ' + (l.lastName || ''),
  title: l.jobTitle || l.title || '',
  company: l.company || '',
  acceptedAt: l.acceptedAt || l.updatedAt || '',
  score: l.score || 0,
  daysSinceAccept: l.acceptedAt ? Math.floor((Date.now() - new Date(l.acceptedAt).getTime()) / 86400000) : '?'
}))).slice(0, 1200);
const today = new Date().toLocaleDateString('it-IT', { weekday: 'long', day: 'numeric', month: 'long' });
const prompt = 'Sei un sales assistant LinkedIn. Oggi è ' + today + '. Il bot è in modalità ' + riskAction + ' (risk ' + riskScore + '/100).\n\nLEAD ACCETTATI DI RECENTE (ultimi 3 giorni):\n' + leadsJson + '\n\nCrea un piano di follow-up per oggi. Considera che il timing ottimale per il primo messaggio è 24-48h dopo l\'accettazione. Se il risk è HIGH o CRITICAL, suggerisci meno messaggi.\n\nOutput in italiano:\n\n📬 *Follow-up di oggi*\n[lista lead a cui inviare oggi, con testo suggerito breve 2-3 righe per ciascuno]\n\n⏳ *Da rimandare*\n[lead troppo recenti o da contattare domani]\n\n💡 *Nota di rischio*\n[1 riga basata su riskAction]';
const claudeBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 900, messages: [{ role: 'user', content: prompt }] });
return [{ json: { claudeBody, leadsCount: arr.length } }];

const response = $input.first().json;
const meta = $('Prepara Prompt').first().json;
let planText = 'Piano non disponibile — errore Claude.';
try {
  const text = response.content?.[0]?.text || '';
  if (text.length > 10) planText = text;
} catch(e) {}
return [{ json: { planText, leadsCount: meta.leadsCount } }];
